# Pseudocode: AI tool access request handler that gates on AUP training completion
# This would run as part of an IAM/provisioning workflow

from dataclasses import dataclass
from datetime import datetime, timezone
from enum import Enum


class TrainingStatus(Enum):
    NOT_ASSIGNED = "not_assigned"
    IN_PROGRESS = "in_progress"
    FAILED_KNOWLEDGE_CHECK = "failed_knowledge_check"
    AWAITING_ATTESTATION = "awaiting_attestation"
    COMPLETE = "complete"
    EXPIRED = "expired"  # Annual renewal overdue


@dataclass
class AttestationRecord:
    employee_id: str
    policy_version: str
    training_module_version: str
    training_completed_at: datetime
    attested_at: datetime
    knowledge_check_score: float  # 0.0 to 1.0


def request_ai_tool_access(employee_id: str, tool_id: str, lms_client, iam_client) -> dict:
    """Process an AI tool access request, gating on AUP training completion."""
    training_status = lms_client.get_aup_training_status(employee_id)

    if training_status == TrainingStatus.COMPLETE:
        # Check attestation is not expired
        record: AttestationRecord = lms_client.get_latest_attestation(employee_id)
        days_since_attestation = (datetime.now(timezone.utc) - record.attested_at).days
        if days_since_attestation > 365:
            lms_client.assign_refresh_training(employee_id)
            return {
                "access_granted": False,
                "reason": "Annual AUP re-attestation required before access continues.",
                "action": "training_assigned",
            }
        # Training current — provision access
        iam_client.provision_tool_access(employee_id, tool_id)
        return {"access_granted": True, "attestation_expires": record.attested_at}

    elif training_status == TrainingStatus.NOT_ASSIGNED:
        lms_client.assign_onboarding_training(employee_id)
        return {
            "access_granted": False,
            "reason": "AUP training assigned. Complete training and attestation to access AI tools.",
            "action": "training_assigned",
        }
    else:
        return {
            "access_granted": False,
            "reason": f"AUP training status: {training_status.value}. Complete training to proceed.",
        }
